mapper.select:
SELECT
    g.*,
    s.name as student_name,
    s.student_no,
    co.course_name,
    cl.class_name
FROM edu_grade g
LEFT JOIN edu_student s ON g.student_id = s.id
LEFT JOIN edu_course co ON g.course_id = co.id
LEFT JOIN edu_class cl ON s.class_id = cl.id


        AND g.student_id = #{studentId}


        AND g.course_id = #{courseId}


        AND g.semester = #{semester}


        AND g.grade_status = #{gradeStatus}


        AND g.teaching_assignment_id = #{teachingAssignmentId}


ORDER BY g.id DESC

SELECT g.*, co.course_name, co.course_code, co.credits as credit FROM edu_grade g LEFT JOIN edu_course co ON g.course_id = co.id WHERE g.student_id = #{studentId}
AND g.semester = #{semester}
ORDER BY g.semester DESC, g.id DESC

mapper.insert:
INSERT INTO edu_grade (
    student_id, course_id, teaching_assignment_id, semester,
    midterm_score, final_score, practice_score, total_score,
    makeup_score, grade_status, input_by, input_time
)
VALUES (
    #{studentId}, #{courseId}, #{teachingAssignmentId}, #{semester},
    #{midtermScore}, #{finalScore}, #{practiceScore}, #{totalScore},
    #{makeupScore}, #{gradeStatus}, #{inputBy}, #{inputTime}
)

mapper.update:
UPDATE edu_grade
midterm_score = #{midtermScore}, final_score = #{finalScore}, practice_score = #{practiceScore}, total_score = #{totalScore}, makeup_score = #{makeupScore}, grade_status = #{gradeStatus}, input_by = #{inputBy}, input_time = #{inputTime},
WHERE id = #{id}

mapper.select:
SELECT ROUND(AVG(total_score), 3) as avgScore, MAX(total_score) as maxScore, MIN(total_score) as minScore, COUNT(1) as totalCount, SUM(CASE WHEN total_score >= 60 THEN 1 ELSE 0 END) as passCount, ROUND(SUM(CASE WHEN total_score >= 60 THEN 1 ELSE 0 END) * 100.0 / COUNT(1), 1) as passRate, ROUND(SUM(CASE WHEN total_score >= 90 THEN 1 ELSE 0 END) * 100.0 / COUNT(1), 1) as excellentRate, ROUND(STDDEV_POP(total_score), 2) as stdDev FROM edu_grade g LEFT JOIN edu_student s ON g.student_id = s.id
AND g.course_id = #{courseId}
AND s.class_id = #{classId}
AND g.semester = #{semester}

SELECT t.level, t.count, ROUND(t.count * 100.0 / GREATEST(t.total, 1), 1) as percentage FROM ( SELECT CASE WHEN total_score >= 90 THEN '优秀' WHEN total_score >= 80 THEN '良好' WHEN total_score >= 70 THEN '中等' WHEN total_score >= 60 THEN '及格' ELSE '不及格' END as level, COUNT(1) as count, (SELECT COUNT(1) FROM edu_grade g2 LEFT JOIN edu_student s2 ON g2.student_id = s2.id WHERE 1=1
AND g2.course_id = #{courseId}
AND s2.class_id = #{classId}
AND g2.semester = #{semester}
) as total FROM edu_grade g LEFT JOIN edu_student s ON g.student_id = s.id
AND g.course_id = #{courseId}
AND s.class_id = #{classId}
AND g.semester = #{semester}
GROUP BY level ) t
